class Solution:
    def arrayNesting(self, nums):
        best = 0
        n = len(nums)
        for start in range(n):
            seen = set()
            cur = start
            while cur not in seen:
                seen.add(cur)
                cur = nums[cur]
            best = max(best, len(seen))
        return best

