class Solution:
    def arrayNesting(self, nums):
        n = len(nums)
        visited = [False] * n
        best = 0
        for i in range(n):
            if visited[i]:
                continue
            cur = i
            length = 0
            while not visited[cur]:
                visited[cur] = True
                cur = nums[cur]
                length += 1
            if length > best:
                best = length
        return best

