var arrayNesting = function(nums) {
    const n = nums.length;
    const visited = new Array(n).fill(false);
    let best = 0;
    for (let i = 0; i < n; i++) {
        if (visited[i]) continue;
        let cur = i;
        let length = 0;
        while (!visited[cur]) {
            visited[cur] = true;
            cur = nums[cur];
            length++;
        }
        if (length > best) best = length;
    }
    return best;
};
